
const API="/api";
let tok=localStorage.tip_token||"",me=null,data=null,page="home",msg="",filter="all",phase="all",betsFilter="all",timer=null;
let draftBets={},editingUntil=0;
const root=document.getElementById('root');
const esc=s=>String(s??"").replace(/[&<>\"]/g,m=>({"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;"}[m]));
const norm=s=>String(s||"").trim();
async function api(p,o={}){let h={"content-type":"application/json"};if(tok)h.authorization="Bearer "+tok;let r=await fetch(API+p,{...o,headers:h,cache:"no-store"});let txt=await r.text();let j={};try{j=txt?JSON.parse(txt):{}}catch{let hint=txt&&txt.trim().startsWith('<')?"/api vrací HTML místo JSON. Zkontroluj Cloudflare Pages: Functions directory musí být functions, D1 binding DB a public/_routes.json musí obsahovat /api a /api/*.":"Server nevrátil JSON.";throw Error(hint)};if(!r.ok)throw Error(j.error||"Chyba API");return j}
async function load(silent=false){try{if(tok){let m=await api('/me');me=m.user;data=await api('/app')}else{me=null;data=null}}catch(e){if(!silent)msg=e.message;localStorage.removeItem('tip_token');tok='';me=null;data=null}render()}
function startRealtime(){clearInterval(timer);timer=setInterval(refreshSilent,5000)}
async function refreshSilent(){if(!me||Date.now()<editingUntil)return;try{data=await api('/app');me=(await api('/me')).user;render()}catch(e){}}
document.addEventListener('visibilitychange',()=>{if(!document.hidden&&me)refreshSilent()});
function go(p){page=p;render()}function out(){localStorage.removeItem('tip_token');tok='';me=null;data=null;msg='';render()}
function sectionTitle(){return ({home:'Domů',tips:'Zápasy',rank:'Pořadí',rules:'Pravidla',profile:'Profil',bets:'Tipy všech',admin:'Admin'})[page]||'Domů'}
function competition(){let s=(data&&data.settings)||{};return {name:s.competition_name||'FIFA World Cup 2026',subtitle:s.competition_subtitle||'MS ve fotbale 2026'}}
function userName(){return me?(me.public_name||me.nick||me.full_name||'hráč'):'hráč'}
function userStats(){let st=(data&&data.meStats)||me||{},rank=(data&&data.ranking)||[],pos=rank.findIndex(x=>x.id==st.id)+1,pct=st.evaluated_count?Math.round(((st.hit_1||0)+(st.hit_3||0))/(st.evaluated_count||1)*100):0;return {st,pos,pct,ev:st.evaluated_count||0}}
function topbar(){if(!me||!data)return'';let c=competition(),u=userName(),{st,pos,pct,ev}=userStats();let total=st.tips_count||0;return `<header class=top><div class=top-inner><div class=brand><img src="app-icon.png?v=66" alt="TIP"><div><div class=brand-title>Tipovačka</div><div class=brand-sub>${esc(c.name)}</div></div></div><div class=header-meta><div class=meta-block><div class=meta-label>sekce</div><div class=meta-value>${esc(sectionTitle())}</div></div><div class=meta-block><div class=meta-label>přihlášen</div><div class="meta-value green">${esc(u)}</div></div></div><div class=top-stats><div class=stat-chip><strong>${pos||'—'}.</strong><span>místo</span></div><div class=stat-chip><strong>${st.points||0}</strong><span>bodů</span></div><div class=stat-chip><strong>${pct}%</strong><span>úspěšnost</span></div><div class=stat-chip><strong>${ev}/${total}</strong><span>vyhodnoceno / tipy</span></div></div></div></header>`}
function navIcon(k){return {home:'<svg viewBox="0 0 24 24"><path d="M3 11.5 12 4l9 7.5"/><path d="M5.5 10.5V20h13v-9.5"/><path d="M9.5 20v-6h5v6"/></svg>',tips:'<svg viewBox="0 0 24 24"><circle cx="12" cy="12" r="8"/><circle cx="12" cy="12" r="4"/><path d="M12 2v3M12 19v3M2 12h3M19 12h3"/></svg>',rank:'<svg viewBox="0 0 24 24"><path d="M8 21h8"/><path d="M12 17v4"/><path d="M7 4h10v4a5 5 0 0 1-10 0V4Z"/><path d="M7 6H4a3 3 0 0 0 3 5"/><path d="M17 6h3a3 3 0 0 1-3 5"/></svg>',profile:'<svg viewBox="0 0 24 24"><circle cx="12" cy="8" r="4"/><path d="M4 21a8 8 0 0 1 16 0"/></svg>',rules:'<svg viewBox="0 0 24 24"><path d="M6 3h9l3 3v15H6z"/><path d="M14 3v4h4"/><path d="M8 11h8M8 15h8M8 19h5"/></svg>',admin:'<svg viewBox="0 0 24 24"><path d="M12 3 20 6v6c0 5-3.5 8-8 9-4.5-1-8-4-8-9V6l8-3Z"/><path d="M9 12l2 2 4-5"/></svg>'}[k]||''}
function nav(){if(!me)return'';let admin=['admin','superadmin'].includes(me.role);let items=[['home','Domů'],['tips','Zápasy'],['rank','Pořadí'],['rules','Pravidla'],['profile','Profil'],['admin','Admin']];return `<nav class=bottom>${items.map(i=>i[0]=='admin'&&!admin?'':`<button class="${page==i[0]?'on':''}" onclick="go('${i[0]}')">${navIcon(i[0])}<span>${i[1]}</span></button>`).join('')}</nav>`}
function loginScreen(){let cname='FIFA World Cup 2026';return `<div class=login><div class=login-card><div class=login-brand><img src="app-icon.png?v=66" alt="TIP"><div><div class=login-brand-title>Tipovačka</div><div class=login-brand-sub>${cname}</div></div></div><p class=note>Tipuj výsledky zápasů, sleduj pořadí a porovnej se s ostatními. Veřejně se zobrazuje jen přezdívka.</p><p class="note" style="font-size:11px;opacity:.65">verze v67-skupiny</p>${msg?`<div class="notice bad">${esc(msg)}</div>`:''}<div class=grid2><input id=loginFirst class=input autocomplete=given-name placeholder="Jméno"><input id=loginLast class=input autocomplete=family-name placeholder="Příjmení"></div><input id=lp class=input type=password autocomplete=current-password placeholder="Heslo"><div class=login-actions><button class="btn primary full" onclick="login(this)">Přihlásit</button><button class="btn full" onclick="toggleRegister(this)">Registrace</button></div><button class="btn small full" style="margin-top:8px" onclick="showForgot(this)">Zapomenuté heslo</button><div id=forgot class="forgot-box hide"><b>Zapomenuté heslo</b><p class=note>Napiš správci soutěže na <b>tomas.nova9@seznam.cz</b>. Do zprávy uveď jméno, příjmení a přezdívku. Správce ti nastaví nové heslo. Původní heslo se z bezpečnostních důvodů nikde nezobrazuje.</p></div><div id=reg class=hide><div class=grid2><input id=first class=input placeholder="Jméno"><input id=last class=input placeholder="Příjmení"></div><input id=nick class=input placeholder="Přezdívka do pořadí"><input id=email class=input placeholder="E-mail"><input id=rp class=input type=password placeholder="Heslo"><input id=code class=input placeholder="Vstupní kód"><button class="btn primary full" onclick="register(this)">Registrovat</button><p class=note>Po registraci najdeš pokyny k platbě v profilu. Admin po spárování platby účet aktivuje.</p></div><div class=login-install><b>📱 Přidání na plochu</b><p class=note><b>iPhone:</b> otevři v Safari → Sdílet → Přidat na plochu.<br><b>Android:</b> otevři v Chrome → menu → Přidat na plochu.</p></div></div></div>`}
function setLoading(btn,label){if(!btn)return()=>{};btn.classList.add('busy');btn.disabled=true;btn.setAttribute('aria-busy','true');return()=>{btn.classList.remove('busy');btn.disabled=false;btn.removeAttribute('aria-busy')}}
function toggleRegister(btn){btn&&btn.classList.add('flash-ok');setTimeout(()=>btn&&btn.classList.remove('flash-ok'),300);let r=document.getElementById('reg');if(r)r.classList.toggle('hide')}
function showForgot(btn){btn&&btn.classList.add('flash-ok');setTimeout(()=>btn&&btn.classList.remove('flash-ok'),300);let f=document.getElementById('forgot');if(f)f.classList.toggle('hide')}
document.addEventListener('click',e=>{const b=e.target.closest&&e.target.closest('button');if(!b||b.disabled)return;b.classList.add('tap-feedback','flash-ok');setTimeout(()=>b.classList.remove('tap-feedback','flash-ok'),220)});
async function login(btn){
  const done=setLoading(btn);
  try{
    msg='';
    const firstEl=document.getElementById('loginFirst');
    const lastEl=document.getElementById('loginLast');
    const passEl=document.getElementById('lp');
    const firstRaw=(firstEl&&firstEl.value?firstEl.value:'').trim();
    const lastRaw=(lastEl&&lastEl.value?lastEl.value:'').trim();
    const pass=(passEl&&passEl.value?passEl.value:'');
    const firstNorm=norm(firstRaw);
    const isAdmin=['admin','administrator'].includes(firstNorm.toLowerCase());
    const full=(firstRaw+' '+lastRaw).trim();
    if(!firstRaw || !pass) throw Error('Vyplň jméno a heslo.');
    if(!lastRaw && !isAdmin) throw Error('Vyplň příjmení.');
    // Posíláme více názvů polí kvůli kompatibilitě se starší/nasazenou funkcí.
    // Starší backend očekával `login`, nový umí `first/last/name`.
    const payload={
      first:firstRaw,
      last:lastRaw,
      name:full,
      login:full || firstRaw,
      username:full || firstRaw,
      password:pass,
      pass:pass
    };
    let r=await api('/auth/login',{method:'POST',body:JSON.stringify(payload)});
    tok=r.token;
    localStorage.tip_token=tok;
    await load();
  }catch(e){
    msg=e.message;
    done();
    render();
  }
}
async function register(btn){const done=setLoading(btn);try{msg='';let r=await api('/auth/register',{method:'POST',body:JSON.stringify({first:first.value,last:last.value,nick:nick.value,email:email.value,phone:(document.getElementById('phone')?.value||''),password:rp.value,code:code.value})});tok=r.token;localStorage.tip_token=tok;await load()}catch(e){msg=e.message;done();render()}}
function dateKey(dt){let d=new Date(dt),n=new Date();let t=new Date(n.getFullYear(),n.getMonth(),n.getDate()).getTime();let x=new Date(d.getFullYear(),d.getMonth(),d.getDate()).getTime();return x==t?'today':x==t+86400000?'tomorrow':'other'}
function left(m){let d=new Date(m.start_time)-new Date();if(d<=0)return'uzamčeno';let s=Math.floor(d/1000),days=Math.floor(s/86400);s%=86400;let h=Math.floor(s/3600);s%=3600;let min=Math.floor(s/60);return days?`${days}d ${h}h ${min}m`:`${h}h ${min}m`}
function displayUser(u){return esc(u.nick||u.public_name||u.full_name||'?')}
function roleLabel(r){return r=='admin'?'Admin':r=='superadmin'?'Superadmin':'Tipér'}
function flagOf(team){
  if(!data) return '';
  const flags=data.teamFlags||{};
  if(flags[team]) return flags[team];
  const m=(data.matches||[]).find(x=>x.home===team||x.away===team);
  if(m) return m.home===team?(m.home_flag||''):(m.away_flag||'');
  if(/^(1|2|3)[A-L]$/.test(String(team||''))||/Vítěz|Poražený|M\d+|TBD|postup|Dopln/i.test(String(team||''))) return '▫️';
  return '🏳️';
}
function teamSelect(id,selected=''){
  const opts=(data&&data.teamOptions?data.teamOptions:[]).filter(Boolean);
  return `<select id="${id}" class="input">${opts.map(t=>`<option value="${esc(t)}" ${t===selected?'selected':''}>${esc(flagOf(t))} ${esc(t)}</option>`).join('')}</select>`;
}

function defaultRulesHtml(){return `<h2>Pravidla a návod k tipovačce</h2><p>Vítej v tipovačce k soutěži <b>FIFA World Cup 2026</b>. Tipuješ přesné výsledky zápasů, sbíráš body a porovnáváš se s ostatními tipéry. Aplikace průběžně ukazuje tvoje body, pořadí, uložené tipy i výsledky ostatních hráčů po uzamčení zápasu.</p><div class=rules-toc><a href="#rules-tipovani">⚽ Jak tipovat</a><a href="#rules-body">🎯 Bodování</a><a href="#rules-ostatni">👥 Tipy ostatních</a><a href="#rules-poradi">📊 Pořadí</a><a href="#rules-zapasy">🗓️ Zápasy</a><a href="#rules-platba">💳 Platba</a><a href="#rules-instalace">📱 Přidání na plochu</a></div><h2 id=rules-tipovani>⚽ Jak tipovat</h2><ul><li>U každého zápasu zadáš přesný výsledek, například <b>2 : 1</b>.</li><li>Tip můžeš před výkopem kdykoliv změnit.</li><li>Po začátku utkání se tipování automaticky uzamkne.</li><li>Pokud zápas nestihneš tipnout, za tento zápas získáš 0 bodů.</li></ul><div class=example><b>Příklad tipu:</b><br>Česko – Německo<br>Tvůj tip: <b>2 : 1</b></div><h2 id=rules-body>🎯 Bodování</h2><h3>Přesný výsledek – 3 body</h3><p>Když trefíš přesné skóre zápasu, získáš <b>3 body</b>.</p><div class=example>Tip: 2 : 1<br>Výsledek: 2 : 1<br><b>+3 body</b></div><h3>Trefená výhra/remíza/prohra – 1 bod</h3><p>Když netrefíš přesné skóre, ale správně určíš, jestli vyhraje domácí tým, hostující tým nebo bude remíza, získáš <b>1 bod</b>.</p><div class=example>Tip: 3 : 1<br>Výsledek: 2 : 1<br>Trefený vítěz<br><b>+1 bod</b></div><h3>Špatný tip – 0 bodů</h3><p>Když netrefíš vítěze/remízu ani přesné skóre, nezískáváš žádný bod.</p><h2 id=rules-ostatni>👥 Tipy ostatních hráčů</h2><ul><li>Před uzavřením tipování vidíš pouze svůj vlastní tip.</li><li>Po uzamčení zápasu se zobrazí tipy ostatních hráčů.</li><li>Po vyhodnocení zápasu uvidíš všechny tipy, skutečný výsledek a přidělené body.</li><li>Tím je zajištěno, že nikdo nemůže před začátkem utkání opisovat tipy ostatních.</li></ul><h2 id=rules-poradi>📊 Pořadí a tabulka</h2><p>Pořadí se aktualizuje automaticky po vyhodnocení zápasu administrátorem.</p><ol><li>Nejdříve rozhoduje celkový počet bodů.</li><li>Při shodě rozhoduje počet přesných tipů za 3 body.</li><li>Poté rozhoduje počet trefených výher/remíz/proher za 1 bod.</li><li>Následně rozhoduje úspěšnost tipování.</li><li>Pokud jsou všechny hodnoty shodné, hráči sdílejí stejné pořadí.</li></ol><table><tr><th>Sloupec</th><th>Význam</th></tr><tr><td>1b</td><td>Kolikrát hráč trefil výhru, remízu nebo prohru.</td></tr><tr><td>3b</td><td>Kolikrát hráč trefil přesný výsledek.</td></tr><tr><td>Body</td><td>Celkový počet bodů.</td></tr></table><p>Počet vyhodnocených tipů a úspěšnost najdeš v dashboardu a v profilu hráče. V hlavní tabulce pořadí zůstávají jen nejdůležitější údaje, aby byla dobře čitelná na telefonu.</p><h2 id=rules-zapasy>🗓️ Zápasy a fáze turnaje</h2><ul><li>Skupinová fáze obsahuje <b>72 zápasů</b> – skupiny A až L, každá skupina má 6 utkání.</li><li>Vyřazovací část obsahuje <b>32 zápasů</b>.</li><li>U skupin jsou týmy, vlajky a termíny předpřipravené.</li><li>U vyřazovací části jsou předpřipravené termíny a pozice. Konkrétní týmy se doplní až po postupu ze skupin.</li><li>Administrátor může později doplnit nebo upravit týmy ve vyřazovací části bez zásahu do celé aplikace.</li></ul><h2>👤 Účet a přezdívka</h2><ul><li>Při registraci zadáváš jméno, příjmení, přezdívku, e-mail a heslo.</li><li>Ostatní hráči vidí pouze tvoji přezdívku.</li><li>Jméno, příjmení a e-mail vidí pouze administrátor.</li><li>Každý hráč může mít pouze jeden účet.</li></ul><h2 id=rules-platba>💳 Platba a aktivace účtu</h2><ul><li>Po registraci účet čeká na aktivaci.</li><li>Pokyny k platbě najdeš po přihlášení v sekci <b>Profil</b>.</li><li>Do zprávy pro příjemce uveď svůj údaj do platby, například <b>TIP-KANONYR89</b>.</li><li>Po spárování platby administrátor účet aktivuje.</li><li>Tipovat a soutěžit mohou pouze aktivované účty.</li></ul><h2>🔄 Vyhodnocení zápasů</h2><ul><li>Výsledky zadává administrátor.</li><li>Po zadání výsledku se body přepočítají automaticky.</li><li>Pořadí, profil i dashboard se aktualizují automaticky.</li></ul><h2 id=rules-instalace>📱 Přidání aplikace na plochu</h2><h3>iPhone / iPad</h3><ol><li>Otevři aplikaci v Safari.</li><li>Klepni na ikonu Sdílet.</li><li>Vyber <b>Přidat na plochu</b>.</li></ol><h3>Android</h3><ol><li>Otevři aplikaci v Chrome.</li><li>Otevři menu prohlížeče.</li><li>Vyber <b>Přidat na plochu</b>.</li></ol><h2>ℹ️ Důležité informace</h2><ul><li>Nepředávej své přihlašovací údaje jiným osobám.</li><li>Při technických problémech kontaktuj administrátora soutěže.</li><li>Organizátor může pravidla doplnit nebo upřesnit, pokud to bude potřeba pro férový průběh soutěže.</li></ul>`}
function scheduleStats(){let ms=data&&data.matches?data.matches:[],groupsList=ms.filter(m=>(m.phase||'').startsWith('Skupina')),knockList=ms.filter(m=>!(m.phase||'').startsWith('Skupina')),groups=groupsList.length,knock=knockList.length,shown=filtered().length;let finished=ms.filter(m=>m.effective_status=='finished').length,groupFinished=groupsList.filter(m=>m.effective_status=='finished').length,knockFinished=knockList.filter(m=>m.effective_status=='finished').length;let phaseCounts={},phaseFinished={};for(const m of ms){phaseCounts[m.phase]=(phaseCounts[m.phase]||0)+1;if(m.effective_status=='finished')phaseFinished[m.phase]=(phaseFinished[m.phase]||0)+1}return {total:ms.length,groups,knock,shown,finished,groupFinished,knockFinished,phaseCounts,phaseFinished}}
function phaseExpected(name){if((name||'').startsWith('Skupina'))return 6;if(name==='32 postupujících')return 16;if(name==='Osmifinále')return 8;if(name==='Čtvrtfinále')return 4;if(name==='Semifinále')return 2;if(name==='O 3. místo')return 1;if(name==='Finále')return 1;return ''}
function scheduleCountsHtml(){let s=scheduleStats();let isAdmin=me&&['admin','superadmin'].includes(me.role);let order=['Skupina A','Skupina B','Skupina C','Skupina D','Skupina E','Skupina F','Skupina G','Skupina H','Skupina I','Skupina J','Skupina K','Skupina L','32 postupujících','Osmifinále','Čtvrtfinále','Semifinále','O 3. místo','Finále'];let small=`<div class=live-counts><div><b>${s.groupFinished}/${s.groups}</b><span>skupiny vyhodnoceno</span></div><div><b>${s.knockFinished}/${s.knock}</b><span>vyřazovací vyhodnoceno</span></div><div><b>${s.shown}</b><span>zobrazeno</span></div></div>`; if(!isAdmin)return small;return small+`<div class=schedule-counts><div class=count-pill><b>${s.total}/104</b><span>celkem v rozpisu</span></div><div class=count-pill><b>${s.groups}/72</b><span>skupinová fáze</span></div><div class=count-pill><b>${s.knock}/32</b><span>vyřazovací část</span></div><div class=count-pill><b>${s.finished}</b><span>vyhodnoceno celkem</span></div></div><div class=phase-breakdown>${order.map(p=>`<div class=phase-pill><b>${esc(p)}</b><span>${s.phaseFinished[p]||0}/${s.phaseCounts[p]||0}${phaseExpected(p)?' z '+phaseExpected(p):''}</span></div>`).join('')}</div>`}
function badge(m){let has=data.bets&&data.bets.find(b=>b.match_id==m.id),st=m.effective_status;if(st=='open')return has?`<span class="badge open">tipnuto</span>`:`<span class="badge open">netipnuto</span>`;return st=='finished'?`<span class="badge done">vyhodnoceno</span>`:`<span class="badge locked">zamčeno</span>`}
function phases(){return ['all',...Array.from(new Set((data.matches||[]).map(m=>m.phase))).filter(Boolean)]}
function filtered(){let arr=[...(data.matches||[])];if(filter=='today')arr=arr.filter(m=>dateKey(m.start_time)=='today');if(filter=='tomorrow')arr=arr.filter(m=>dateKey(m.start_time)=='tomorrow');if(filter=='missing')arr=arr.filter(m=>!data.bets.find(b=>b.match_id==m.id)&&m.effective_status=='open');if(filter=='tipped')arr=arr.filter(m=>data.bets.find(b=>b.match_id==m.id));if(filter=='open')arr=arr.filter(m=>m.effective_status=='open');if(filter=='locked')arr=arr.filter(m=>m.effective_status=='locked');if(filter=='finished')arr=arr.filter(m=>m.effective_status=='finished');if(phase!='all')arr=arr.filter(m=>m.phase==phase);return arr}
function scoreStepper(id,val,lock){let v=draftBets[id]??val??0;return `<div class=stepper><button class=btn onclick="step('${id}',-1)" ${lock?'disabled':''}>−</button><div id="${id}" class=stepper-value>${v}</div><button class=btn onclick="step('${id}',1)" ${lock?'disabled':''}>+</button></div>`}
function step(id,delta){let el=document.getElementById(id);if(!el)return;let v=Math.max(0,Number(el.textContent||0)+delta);el.textContent=v;draftBets[id]=v;editingUntil=Date.now()+25000}
async function bet(id){try{let h=Number(document.getElementById('h_'+id).textContent),a=Number(document.getElementById('a_'+id).textContent);await api('/bets',{method:'POST',body:JSON.stringify({matchId:id,homeGoals:h,awayGoals:a})});delete draftBets['h_'+id];delete draftBets['a_'+id];editingUntil=0;await refreshSilent()}catch(e){alert(e.message)}}
function scoreClass(x,m){if(!m.score)return'';let [h,a]=m.score.split(':').map(Number);if(Number(x.home_goals)==h&&Number(x.away_goals)==a)return'exact-hit';let pick=h>a?'1':h<a?'2':'X';return x.pick==pick?'win':''}
function otherBetsHtml(m){let arr=(data.publicBets||[]).filter(x=>x.match_id==m.id);if(m.effective_status=='open')return `<div class=note>Tipy ostatních se zobrazí po uzamčení zápasu.</div>`;return `<div class=others><b>Tipy ostatních</b>${arr.length?arr.map(x=>`<div class=others-row><span>${esc(x.nick||x.public_name)}</span><b class="${scoreClass(x,m)}">${x.home_goals}:${x.away_goals}</b></div>`).join(''):`<div class=note>Nikdo zatím netipoval.</div>`}</div>`}
function filtersHtml(){let items=[['all','Vše'],['open','Otevřené'],['missing','Netipnuté'],['tipped','Tipnuté'],['finished','Vyhodnocené']];return `<div class="card filters-card"><div class=filter-grid>${items.map(x=>`<button class="btn ${filter==x[0]?'active':''}" onclick="filter='${x[0]}';render()">${x[1]}</button>`).join('')}</div><select class="input phase-select" onchange="phase=this.value;render()">${phases().map(p=>`<option value="${esc(p)}" ${phase==p?'selected':''}>${p=='all'?'Všechny skupiny a fáze':esc(p)}</option>`).join('')}</select>${scheduleCountsHtml()}</div>`}
function upcomingMissingMatches(){
  const now=new Date();
  return (data.matches||[])
    .filter(m=>m.effective_status==='open' && new Date(m.start_time)>now && !(data.bets||[]).find(b=>b.match_id===m.id))
    .sort((a,b)=>new Date(a.start_time)-new Date(b.start_time));
}
function nextOpenMatch(){
  const now=new Date();
  return (data.matches||[]).filter(m=>m.effective_status==='open' && new Date(m.start_time)>now).sort((a,b)=>new Date(a.start_time)-new Date(b.start_time))[0];
}
function lastFinishedMatch(){
  return (data.matches||[]).filter(m=>m.score || m.effective_status==='finished').sort((a,b)=>new Date(b.start_time)-new Date(a.start_time))[0];
}
function matchMini(m){
  if(!m)return '<div class=note>Žádný nejbližší zápas není k dispozici.</div>';
  return `<div class=next-match-mini><div class=team-mini><div class=flag>${esc(m.home_flag||'')}</div>${esc(m.home)}</div><b>VS</b><div class=team-mini><div class=flag>${esc(m.away_flag||'')}</div>${esc(m.away)}</div></div><div class=note>${new Date(m.start_time).toLocaleString('cs-CZ')} • ${esc(m.phase||'')}</div>`;
}
function notifyText(missing){
  if(!missing.length)return `<div class="notice ok">Máš tipnuto všechno, co je teď otevřené. Skvělá práce.</div>`;
  const m=missing[0];
  return `<div class=soft-alert><b>Ještě zbývá tipnout ${missing.length} zápas${missing.length==1?'':'ů'}.</b><br><span class=tiny>Nejbližší netipnutý zápas: ${esc(m.home_flag||'')} ${esc(m.home)} vs ${esc(m.away_flag||'')} ${esc(m.away)} • ${new Date(m.start_time).toLocaleString('cs-CZ')}</span><div class=notify-row><button class="btn primary" onclick="filter='missing';page='tips';render()">Tipnout teď</button><button class="btn ghost" onclick="enableNotify()">Povolit připomenutí</button></div></div>`;
}
function enableNotify(){
  try{
    localStorage.tip_notify='1';
    if('Notification' in window && Notification.permission==='default') Notification.requestPermission();
    alert('Hotovo. V aplikaci se budou zvýrazňovat netipnuté zápasy. Skutečné push notifikace mimo otevřený prohlížeč by vyžadovaly samostatné serverové oznámení.');
  }catch(e){alert('Připomenutí se nepodařilo povolit.')}
}
function home(){
  let p=data.pool||{}, st=data.meStats||me||{}, ev=st.evaluated_count||0, tipsCount=st.tips_count||0;
  const missing=upcomingMissingMatches();
  const next=nextOpenMatch();
  const last=lastFinishedMatch();
  const fee=(Number(data.settings?.admin_fee||0)+Number(data.settings?.game_fee||0));
  const feeText=fee?`${fee} Kč`:'dle nastavení admina';
  const prize=data.settings?.game_fee?`${data.settings.game_fee} Kč do banku hry`:'dle domluvy soutěže';
  const bank=data.settings?.bank_account||'číslo účtu doplní admin';
  const payNote=`TIP - ${norm((me.first||'')+' '+(me.last||''))||displayUser(me)}`;
  if(me.role!=='player'){
    const waiting=(data.users||[]).filter(u=>u.role==='player'&&(!u.approved||!u.paid)).length;
    const waitingResults=(data.matches||[]).filter(m=>(m.effective_status==='locked'||new Date(m.start_time)<=new Date())&&!m.score).length;
    return `<div class=home-grid><div class="card home-hero"><div class=home-kicker>Admin centrum</div><div class=home-big>Vítej zpět, ${esc(displayUser(me))}</div><p class=note>Rychlý přehled toho, co je potřeba dnes vyřešit.</p><div class=home-actions><button class="btn primary" onclick="page='admin';render();setTimeout(()=>setAdminTab&&setAdminTab('todo'),0)">K vyřešení</button><button class="btn" onclick="page='rank';render()">Zobrazit pořadí</button></div></div><div class=card><div class=title>Rychlý stav</div><div class=pay-list><div class=pay-row><span>Čeká na aktivaci</span><b>${waiting}</b></div><div class=pay-row><span>Čeká na vyhodnocení</span><b>${waitingResults}</b></div><div class=pay-row><span>Aktivních tipérů</span><b>${p.players||0}</b></div></div></div></div>`;
  }
  if(!me.approved||!me.paid){
    return `<div class=home-grid><div class="card home-hero"><div class=home-kicker>Účet čeká na aktivaci</div><div class=home-big>Dokonči registraci platbou</div><p class=note>Po připsání platby tě administrátor aktivuje a zařadí do soutěže. Do té doby se můžeš přihlásit a číst pravidla, ale nepůjde ukládat tipy.</p><div class=pay-list><div class=pay-row><span>Startovné</span><b>${esc(feeText)}</b></div><div class=pay-row><span>Hraje se o</span><b>${esc(prize)}</b></div><div class=pay-row><span>Číslo účtu</span><b>${esc(bank)}</b></div><div class=pay-row><span>Zpráva / poznámka</span><b>${esc(payNote)}</b></div></div></div><div class=card><div class=title>Co dál?</div><ol class=note><li>Pošli platbu podle údajů vlevo.</li><li>Do poznámky napiš přesně uvedený text.</li><li>Po aktivaci se ti odemkne tipování.</li></ol><button class="btn primary full" onclick="page='rules';render()">Přečíst pravidla</button></div></div>`;
  }
  return `<div class=home-grid><div class="card home-hero"><div class=home-kicker>Moje soutěž</div><div class=home-big>${ev}/${tipsCount} vyhodnoceno · ${st.points||0} bodů</div><p class=note>Pořadí se aktualizuje po zadání výsledků administrátorem. Tipy ostatních uvidíš až po uzamčení zápasu.</p>${notifyText(missing)}</div><div class=card><div class=title>Nejbližší zápas</div>${matchMini(next)}<button class="btn full" onclick="page='tips';render()">Otevřít zápasy</button></div></div><div class=home-grid><div class=card><div class=title>Poslední vyhodnocení</div>${last?`<div class=feed-item><b>${esc(last.home_flag||'')} ${esc(last.home)} ${esc(last.score||'')} ${esc(last.away_flag||'')} ${esc(last.away)}</b><div class=note>${esc(last.phase||'')} • pořadí a body jsou přepočítané</div></div>`:'<div class=note>Zatím není vyhodnocený žádný zápas.</div>'}</div><div class=card><div class=title>Rychlé odkazy</div><div class=home-actions><button class="btn primary" onclick="filter='missing';page='tips';render()">Netipnuté</button><button class="btn" onclick="page='rank';render()">Pořadí</button></div></div></div>`;
}
function tips(){let arr=filtered();return filtersHtml()+`<div class=card>${arr.length?arr.map(m=>{let b=data.bets.find(x=>x.match_id==m.id)||{},lock=m.effective_status!='open'||!me.approved||!me.paid||me.role!='player',tipped=!!b.match_id;return `<div class="match ${tipped?'tipped':'missing'}"><div class=match-head><div>${badge(m)}</div><div class=note>${new Date(m.start_time).toLocaleString('cs-CZ')} • ${esc(m.phase)} • ${left(m)}</div></div><div class=teams><div class=team><div class=flag>${esc(m.home_flag||'')}</div>${esc(m.home)}</div><div class=score>${m.score?esc(m.score):'VS'}</div><div class=team><div class=flag>${esc(m.away_flag||'')}</div>${esc(m.away)}</div></div><div class=exact>${scoreStepper('h_'+m.id,b.home_goals??0,lock)}<b>:</b>${scoreStepper('a_'+m.id,b.away_goals??0,lock)}</div><div class=tip-actions><button class="btn primary full" ${lock?'disabled':''} onclick="bet('${m.id}')">${tipped?'Upravit tip':'Potvrdit tip'}</button></div>${tipped?`<div class=saved-tip>✓ Uložený tip: ${b.home_goals}:${b.away_goals}</div>`:''}${otherBetsHtml(m)}</div>`}).join(''):'<div class=notice>Pro filtr nejsou zápasy.</div>'}</div>`}
function rank(){let top=data.ranking||[];let updated=new Date().toLocaleString('cs-CZ');return `<div class=card><div class=rank-table-wrap><div class=rank-table><div class=rank-head><div>#</div><div>Tipér</div><div>1b</div><div>3b</div><div>Body</div></div>${top.length?top.map((u,i)=>`<div class="rank-row ${u.id==me.id?'my-row':''}"><div class=medal>${i==0?'🥇':i==1?'🥈':i==2?'🥉':i+1}</div><div class=rank-nick title="${displayUser(u)}">${displayUser(u)}</div><div class=rank-cell>${u.hit_1||0}</div><div class=rank-cell>${u.hit_3||0}</div><div class="rank-cell rank-total">${u.points||0}</div></div>`).join(''):'<div class=notice>Zatím nejsou vyhodnocené tipy.</div>'}</div></div><div class=rank-legend><b>1b</b> = trefená výhra, remíza nebo prohra. <b>3b</b> = přesný výsledek. <b>Body</b> rozhodují o pořadí. Při shodě rozhodují body, pak 3b, potom 1b a následně úspěšnost tipování.</div><div class=note style="margin-top:8px">Aktualizováno: ${updated}</div></div>`}
function rules(){let r=(data.settings&&data.settings.rules_html)||'';if(!r||r.length<800)r=defaultRulesHtml();return `<div class=card><div class=rules-content>${r}</div></div>`}
async function withBusy(label, fn){
  const btn=document.activeElement && document.activeElement.tagName==='BUTTON' ? document.activeElement : null;
  if(btn){btn.classList.add('busy');btn.disabled=true;btn.setAttribute('aria-busy','true')}
  try{return await fn()}catch(e){alert(e.message||e)}
  finally{if(btn){btn.classList.remove('busy');btn.disabled=false;btn.removeAttribute('aria-busy')}}
}
async function approve(id){await withBusy('Aktivuji…',async()=>{await api('/admin/approve',{method:'POST',body:JSON.stringify({userId:id})});await refreshSilent(true)})}
async function deactivate(id){await withBusy('Vypínám…',async()=>{await api('/admin/deactivate',{method:'POST',body:JSON.stringify({userId:id})});await refreshSilent(true)})}
async function role(id,r){await withBusy('Ukládám…',async()=>{await api('/admin/role',{method:'POST',body:JSON.stringify({userId:id,role:r})});await refreshSilent(true)})}
async function resetPassword(id,nick){let p=prompt('Nové heslo pro '+(nick||'uživatele')+' (min. 4 znaky)');if(!p)return;await withBusy('Nastavuji…',async()=>{await api('/admin/reset-password',{method:'POST',body:JSON.stringify({userId:id,password:p})});await refreshSilent(true);alert('Heslo bylo nastaveno.')})}
async function delUser(id){if(confirm('Smazat hráče i jeho tipy?'))await withBusy('Mažu…',async()=>{await api('/admin/delete-user',{method:'POST',body:JSON.stringify({userId:id})});await refreshSilent(true)})}
async function setStatus(id,st){await withBusy('Ukládám…',async()=>{await api('/admin/status',{method:'POST',body:JSON.stringify({matchId:id,status:st})});await refreshSilent(true)})}
async function result(id){let score=prompt('Výsledek např. 2:1');if(score)await withBusy('Vyhodnocuji…',async()=>{await api('/admin/result',{method:'POST',body:JSON.stringify({matchId:id,score})});await refreshSilent(true)})}
async function editMatch(m){let home=prompt('Domácí tým',m.home);if(!home)return;let away=prompt('Hostující tým',m.away);if(!away)return;let start_time=prompt('Čas ve formátu 2026-06-11T21:00',m.start_time);if(!start_time)return;let ph=prompt('Fáze/skupina',m.phase)||m.phase;await withBusy('Ukládám…',async()=>{await api('/admin/edit-match',{method:'POST',body:JSON.stringify({matchId:m.id,home,away,start_time,phase:ph})});await refreshSilent(true)})}
async function addMatch(){await withBusy('Přidávám…',async()=>{let home=homeTeam.value,away=awayTeam.value;if(!home||!away||!startTime.value){alert('Vyber týmy a čas zápasu.');return}await api('/admin/add-match',{method:'POST',body:JSON.stringify({phase:phaseIn.value,home,away,start_time:startTime.value})});await refreshSilent(true)})}
async function imp(){await withBusy('Importuji…',async()=>{await api('/admin/import',{method:'POST',body:JSON.stringify({text:bulk.value})});await refreshSilent(true);alert('Import hotový')})}
async function recalc(){await withBusy('Přepočítávám…',async()=>{await api('/admin/recalc',{method:'POST'});await refreshSilent(true);alert('Přepočítáno')})}
async function resetSchedule(){if(confirm('Obnovit pevný rozpis MS 2026 uložený v aplikaci? Tím se odstraní staré duplicitní testovací zápasy a ponechá se pevná šablona 104 utkání.'))await withBusy('Obnovuji…',async()=>{let r=await api('/admin/reset-schedule',{method:'POST',body:'{}'});await refreshSilent(true);alert('Rozpis připraven. Přidáno: '+(r.added||0)+' • aktualizováno: '+(r.updated||0)+' • odstraněno duplicit: '+(r.removed||0)+' • celkem v šabloně: '+(r.total||104))})}
async function quickTeams(id,start_time,phase){let h=document.getElementById('kh_'+id).value,a=document.getElementById('ka_'+id).value;await withBusy('Ukládám…',async()=>{await api('/admin/edit-match',{method:'POST',body:JSON.stringify({matchId:id,home:h,away:a,start_time,phase})});await refreshSilent(true)})}
function admin(){if(!['admin','superadmin'].includes(me.role))return `<div class=card><div class=notice>Bez oprávnění.</div></div>`;let phasesList=['Skupina A','Skupina B','Skupina C','Skupina D','Skupina E','Skupina F','Skupina G','Skupina H','Skupina I','Skupina J','Skupina K','Skupina L','32 postupujících','Osmifinále','Čtvrtfinále','Semifinále','O 3. místo','Finále'];let active=(data.users||[]).filter(x=>x.approved&&x.paid).length, waiting=(data.users||[]).length-active, finished=(data.matches||[]).filter(x=>x.effective_status=='finished').length;return `<div class=card><div class=admin-summary><div class=mini><b>${data.users.length}</b><span>hráčů celkem</span></div><div class=mini><b>${active}</b><span>aktivních</span></div><div class=mini><b>${waiting}</b><span>čeká</span></div><div class=mini><b>${finished}/${data.matches.length}</b><span>vyhodnoceno zápasů</span></div></div></div><div class=card><div class=notice ok>API backend aktivní: pokud se při výsledku objeví „/api vrací HTML“, je na serveru nasazená stará nebo statická verze bez functions.</div></div><div class=card><div class=title>Nastavení soutěže</div><input id=compName class=input value="${esc(data.settings.competition_name||'FIFA World Cup 2026')}" placeholder="Název soutěže"><input id=compSub class=input value="${esc(data.settings.competition_subtitle||'MS ve fotbale 2026')}" placeholder="Podtitulek"><div class=grid2><input id=af class=input type=number value="${data.settings.admin_fee||0}" placeholder="Poplatek adminovi"><input id=gf class=input type=number value="${data.settings.game_fee||0}" placeholder="Vklad do hry"></div><input id=bank class=input value="${esc(data.settings.bank_account||'')}" placeholder="Bankovní účet"><input id=access class=input value="${esc(data.settings.access_code||'TIP2026')}" placeholder="Vstupní kód"><textarea id=rulesText class=input placeholder="Pravidla">${esc(data.settings.rules_html||defaultRulesHtml())}</textarea><button class="btn primary full" onclick=saveSettings()>Uložit nastavení</button></div><div class=card><button class="btn good full" onclick=recalc()>Přepočítat body</button></div><div class=card><div class=title>Hráči, kontakty a platby</div><div class=admin-list>${data.users.map(u=>`<div class=admin-row><div class=rank><div class=grow><b>${esc(u.first)} ${esc(u.last)}</b><div class=note>Veřejně: <b>${displayUser(u)}</b> • ${esc(u.email||'bez e-mailu')}<br>Platba: <b>${esc(u.payment_note||'')}</b></div><span class="role ${u.role}">${roleLabel(u.role)}</span> ${u.approved&&u.paid?'<span class="role player">aktivní</span>':'<span class="role admin">čeká</span>'}</div><div class=points>${u.points||0} b</div></div><div class=admin-actions><button class="btn good small" onclick="approve('${u.id}')">Aktivovat</button><button class="btn small" onclick="deactivate('${u.id}')">Deaktivovat</button><button class="btn small" onclick="role('${u.id}','player')">Tipér</button><button class="btn small" onclick="role('${u.id}','admin')">Admin</button><button class="btn small" onclick="resetPassword('${u.id}','${esc(u.nick||u.first)}')">Reset hesla</button><button class="btn danger small" onclick="delUser('${u.id}')">Smazat</button></div></div>`).join('')}</div></div><div class=card><div class=title>Přidat zápas</div><select id=phaseIn class=input>${phasesList.map(x=>`<option>${x}</option>`).join('')}</select><div class=grid2>${teamSelect('homeTeam')} ${teamSelect('awayTeam')}</div><input id=startTime class=input type=datetime-local><button class="btn primary full" onclick=addMatch()>Přidat zápas</button><p class=note>Vybereš zemi ze seznamu a vlajka se doplní automaticky po uložení zápasu.</p></div><div class=card><div class=title>Import zápasů</div><p class=note>Formát: 2026-06-11 21:00; Skupina A; Mexiko; Jihoafrická republika</p><textarea id=bulk class=input></textarea><button class="btn primary full" onclick=imp()>Importovat</button></div><div class=card><div class=title>Doplnění vyřazovací fáze</div><p class=note>Pro zápasy, kde zatím není jasné obsazení, vybereš týmy ručně. Hodí se pro 32 postupujících, osmifinále i další fáze.</p><div class=phase-tools>${(data.matches||[]).filter(m=>m.home=='TBD'||m.away=='TBD'||/^(1|2|3)[A-L]/.test(m.home)||/^(1|2|3)[A-L]/.test(m.away)||/Vítěz|Poražený|M\d+|TBD|postup|Doplní/i.test((m.home||'')+' '+(m.away||'')+' '+(m.info||''))).map(m=>`<div class=phase-row><b>${esc(m.phase)} • ${new Date(m.start_time).toLocaleDateString('cs-CZ')}</b><select id="kh_${m.id}" class=input>${data.teamOptions.map(t=>`<option value="${esc(t)}" ${t==m.home?'selected':''}>${esc(flagOf(t))} ${esc(t)}</option>`).join('')}</select><select id="ka_${m.id}" class=input>${data.teamOptions.map(t=>`<option value="${esc(t)}" ${t==m.away?'selected':''}>${esc(flagOf(t))} ${esc(t)}</option>`).join('')}</select><button class="btn good" onclick="quickTeams('${m.id}','${esc(m.start_time)}','${esc(m.phase)}')">Uložit</button></div>`).join('')||'<div class=notice>Žádný zápas k doplnění.</div>'}</div></div><div class=card><div class=title>Správa zápasů</div><button class="btn good full" onclick=resetSchedule()>Obnovit pevný rozpis MS 2026</button>${data.matches.map(m=>`<div class=match><div class=match-head><b>${esc(m.home_flag||'')} ${esc(m.home)} vs ${esc(m.away_flag||'')} ${esc(m.away)}</b>${badge(m)}</div><div class=note>${esc(m.phase)} • ${new Date(m.start_time).toLocaleString('cs-CZ')} ${m.score?'• '+esc(m.score):''}</div><div class=admin-actions><button class="btn small" onclick='editMatch(${JSON.stringify(m).replace(/'/g,"&#39;")})'>Upravit</button><button class="btn small" onclick="setStatus('${m.id}','open')">Otevřít</button><button class="btn small" onclick="setStatus('${m.id}','locked')">Zamknout</button><button class="btn good small" onclick="result('${m.id}')">Výsledek</button><button class="btn small" onclick="setStatus('${m.id}','finished')">Dohráno</button></div></div>`).join('')}</div>`}

function profile(){
  let u=data.meStats||me||{};
  let pos=(data.ranking||[]).findIndex(x=>x.id==u.id)+1;
  let evaluated=u.evaluated_count||0, tips=u.tips_count||0;
  let pct=evaluated?Math.round(((u.hit_1||0)+(u.hit_3||0))/evaluated*100):0;
  let nick=u.public_name||u.nick||me.public_name||me.nick||me.full_name||'Hráč';
  return `<div class="card profile-hero"><div><div class=profile-nick>${esc(nick)}</div><div class=profile-real>${esc(me.first||'')} ${esc(me.last||'')} ${me.email?'• '+esc(me.email):''}</div></div><div><span class=role-chip>${roleLabel(me.role)}</span></div></div>
  <div class="card profile-grid"><div class=profile-stat><b>${pos||'—'}</b><span>pořadí</span></div><div class=profile-stat><b>${u.points||0}</b><span>bodů</span></div><div class=profile-stat><b>${evaluated}<small>/${tips}</small></b><span>vyhodnoceno / tipy</span></div><div class=profile-stat><b>${pct}%</b><span>úspěšnost</span></div></div>
  <div class=card><div class=profile-data><div class=data-row><span>jméno</span><b>${esc(me.first||'—')}</b></div><div class=data-row><span>příjmení</span><b>${esc(me.last||'—')}</b></div><div class=data-row><span>přezdívka</span><b>${esc(nick)}</b></div><div class=data-row><span>e-mail</span><b>${esc(me.email||'—')}</b></div><div class=data-row><span>role</span><b>${roleLabel(me.role)}</b></div><div class=data-row><span>stav účtu</span><b>${me.approved&&me.paid?'aktivní':'čeká na aktivaci'}</b></div><div class=data-row><span>údaj do platby</span><b>${esc(me.payment_note||'TIP')}</b></div><div class=data-row><span>veřejně viditelné</span><b>jen přezdívka</b></div></div><button class="btn danger full" style="margin-top:14px" onclick=out()>Odhlásit</button></div>`;
}
function betsPage(){
  let ms=(data.matches||[]).filter(m=>m.effective_status!='open');
  return `<div class=card><div class=title>Tipy všech</div><p class=note>Tipy ostatních se zobrazují pouze u zamčených nebo vyhodnocených zápasů.</p>${ms.length?ms.map(m=>`<div class=match><div class=match-head><b>${esc(m.home_flag||'')} ${esc(m.home)} vs ${esc(m.away_flag||'')} ${esc(m.away)}</b>${badge(m)}</div><div class=note>${esc(m.phase)} • ${new Date(m.start_time).toLocaleString('cs-CZ')} ${m.score?'• výsledek '+esc(m.score):''}</div>${otherBetsHtml(m)}</div>`).join(''):'<div class=notice>Zatím není žádný zamčený zápas.</div>'}</div>`;
}


// v37 overrides: less flicker, cleaner admin, compact ranking
let __lastRenderSignature = '';
let adminTab='todo';
function renderSignature(){
  try {
    return JSON.stringify({page, me: me && {id:me.id, role:me.role, nick:me.nick, public_name:me.public_name, approved:me.approved, paid:me.paid}, data});
  } catch(e) { return String(Date.now()) }
}
function setAdminTab(tab){
  adminTab=tab;
  document.querySelectorAll('.admin-panel').forEach(x=>x.classList.remove('active'));
  document.querySelectorAll('.admin-tab').forEach(x=>x.classList.remove('active'));
  let p=document.getElementById('admin-'+tab), b=document.getElementById('tab-'+tab);
  if(p)p.classList.add('active'); if(b)b.classList.add('active');
}
async function saveSettings(){
  try{
    const btn=document.getElementById('saveSettingsBtn'); if(btn){btn.disabled=true;btn.classList.add('busy')}
    await api('/admin/settings',{method:'POST',body:JSON.stringify({
      admin_fee:+af.value||0,
      game_fee:+gf.value||0,
      bank_account:bank.value,
      access_code:access.value,
      rules_html:rulesText.value,
      competition_name:compName.value,
      competition_subtitle:compSub.value,
      competition_logo_url:''
    })});
    const n=document.getElementById('saveNote'); if(n){n.classList.add('show');setTimeout(()=>n.classList.remove('show'),2200)}
    await refreshSilent(true);
  }catch(e){alert(e.message)}
  finally{const btn=document.getElementById('saveSettingsBtn'); if(btn){btn.disabled=false;btn.classList.remove('busy')}}
}
function admin(){
  if(!['admin','superadmin'].includes(me.role))return `<div class=card><div class=notice>Bez oprávnění.</div></div>`;
  let phasesList=['Skupina A','Skupina B','Skupina C','Skupina D','Skupina E','Skupina F','Skupina G','Skupina H','Skupina I','Skupina J','Skupina K','Skupina L','32 postupujících','Osmifinále','Čtvrtfinále','Semifinále','O 3. místo','Finále'];
  let users=data.users||[], matches=data.matches||[];
  let playerUsers=users.filter(x=>x.role==='player');
  let active=playerUsers.filter(x=>x.approved&&x.paid).length, waiting=playerUsers.length-active, finished=matches.filter(x=>x.effective_status=='finished').length;
  let toConfirm=matches.filter(m=>(m.effective_status=='locked'||new Date(m.start_time)<=new Date())&&!m.score).slice(0,18);
  let placeholders=matches.filter(m=>m.home=='TBD'||m.away=='TBD'||/^(1|2|3)[A-L]/.test(m.home)||/^(1|2|3)[A-L]/.test(m.away)||/Vítěz|Poražený|M\d+|TBD|postup|Doplní/i.test((m.home||'')+' '+(m.away||'')+' '+(m.info||'')));
  return `<div class=card><div class=admin-summary><div class=mini><b>${playerUsers.length}</b><span>tipérů celkem</span></div><div class=mini><b>${active}</b><span>aktivních</span></div><div class=mini><b>${waiting}</b><span>čeká</span></div><div class=mini><b>${finished}/${matches.length}</b><span>vyhodnoceno</span></div></div></div>
  <div class=card><div class=admin-tabs><button id=tab-todo class="btn admin-tab ${adminTab=='todo'?'active':''}" onclick="setAdminTab('todo')">K vyřešení</button><button id=tab-users class="btn admin-tab ${adminTab=='users'?'active':''}" onclick="setAdminTab('users')">Hráči</button><button id=tab-settings class="btn admin-tab ${adminTab=='settings'?'active':''}" onclick="setAdminTab('settings')">Nastavení</button><button id=tab-phases class="btn admin-tab ${adminTab=='phases'?'active':''}" onclick="setAdminTab('phases')">Fáze</button><button id=tab-import class="btn admin-tab ${adminTab=='import'?'active':''}" onclick="setAdminTab('import')">Import</button><button id=tab-all class="btn admin-tab ${adminTab=='all'?'active':''}" onclick="setAdminTab('all')">Zápasy</button></div>
  <div id=admin-todo class="admin-panel ${adminTab=='todo'?'active':''}"><div class=title>Co je potřeba vyřešit</div>${toConfirm.length?toConfirm.map(m=>`<div class=todo-match><b>${esc(m.home_flag||'')} ${esc(m.home)} vs ${esc(m.away_flag||'')} ${esc(m.away)}</b><div class=note>${esc(m.phase)} • ${new Date(m.start_time).toLocaleString('cs-CZ')}</div><div class=admin-actions><button class="btn good small" onclick="result('${m.id}')">Zadat výsledek</button><button class="btn small" onclick="setStatus('${m.id}','open')">Znovu otevřít</button></div></div>`).join(''):'<div class=notice>Teď není žádný zápas k vyhodnocení.</div>'}${placeholders.length?`<div class=title style="margin-top:18px">Doplnit týmy ve fázích</div>${placeholders.slice(0,8).map(m=>`<div class=todo-match><b>${esc(m.phase)} • ${new Date(m.start_time).toLocaleDateString('cs-CZ')}</b><div class=grid2><select id="kh_${m.id}" class=input>${data.teamOptions.map(t=>`<option value="${esc(t)}" ${t==m.home?'selected':''}>${esc(flagOf(t))} ${esc(t)}</option>`).join('')}</select><select id="ka_${m.id}" class=input>${data.teamOptions.map(t=>`<option value="${esc(t)}" ${t==m.away?'selected':''}>${esc(flagOf(t))} ${esc(t)}</option>`).join('')}</select></div><button class="btn good full" onclick="quickTeams('${m.id}','${esc(m.start_time)}','${esc(m.phase)}')">Uložit týmy</button></div>`).join('')}`:''}</div>
  <div id=admin-users class="admin-panel ${adminTab=='users'?'active':''}"><div class=title>Hráči, kontakty a platby</div><div class=admin-list>${users.map(u=>`<div class=admin-row><div class=rank><div class=grow><b>${esc(u.first)} ${esc(u.last)}</b><div class=note>Veřejně: <b>${displayUser(u)}</b> • ${esc(u.email||'bez e-mailu')}<br>Platba: <b>${esc(u.payment_note||'')}</b></div><span class="role ${u.role}">${roleLabel(u.role)}</span> ${u.approved&&u.paid?'<span class="role player">aktivní</span>':'<span class="role admin">čeká</span>'}</div><div class=points>${u.points||0} b</div></div><div class=admin-actions><button class="btn good small" onclick="approve('${u.id}')">Aktivovat</button><button class="btn small" onclick="deactivate('${u.id}')">Deaktivovat</button><button class="btn small" onclick="role('${u.id}','player')">Tipér</button><button class="btn small" onclick="role('${u.id}','admin')">Admin</button><button class="btn small" onclick="resetPassword('${u.id}','${esc(u.nick||u.first)}')">Reset hesla</button><button class="btn danger small" onclick="delUser('${u.id}')">Smazat</button></div></div>`).join('')}</div></div>
  <div id=admin-settings class="admin-panel ${adminTab=='settings'?'active':''}"><div class=title>Nastavení soutěže a plateb</div><input id=compName class=input value="${esc(data.settings.competition_name||'FIFA World Cup 2026')}" placeholder="Název soutěže"><input id=compSub class=input value="${esc(data.settings.competition_subtitle||'MS ve fotbale 2026')}" placeholder="Podtitulek"><div class=setting-grid><input id=af class=input type=number value="${data.settings.admin_fee||0}" placeholder="Poplatek adminovi"><input id=gf class=input type=number value="${data.settings.game_fee||0}" placeholder="Vklad do hry"></div><input id=bank class=input value="${esc(data.settings.bank_account||'')}" placeholder="Bankovní účet"><input id=access class=input value="${esc(data.settings.access_code||'TIP2026')}" placeholder="Vstupní kód"><textarea id=rulesText class=input placeholder="Pravidla">${esc(data.settings.rules_html||defaultRulesHtml())}</textarea><button id=saveSettingsBtn class="btn primary full" onclick=saveSettings()>Uložit nastavení</button><div id=saveNote class="notice ok save-note">Nastavení uloženo.</div><button class="btn good full" style="margin-top:10px" onclick=recalc()>Přepočítat body</button></div>
  <div id=admin-phases class="admin-panel ${adminTab=='phases'?'active':''}"><div class=title>Doplnění vyřazovací fáze</div>${placeholders.length?placeholders.map(m=>`<div class=phase-row><b>${esc(m.phase)} • ${new Date(m.start_time).toLocaleDateString('cs-CZ')}</b><select id="kh_${m.id}" class=input>${data.teamOptions.map(t=>`<option value="${esc(t)}" ${t==m.home?'selected':''}>${esc(flagOf(t))} ${esc(t)}</option>`).join('')}</select><select id="ka_${m.id}" class=input>${data.teamOptions.map(t=>`<option value="${esc(t)}" ${t==m.away?'selected':''}>${esc(flagOf(t))} ${esc(t)}</option>`).join('')}</select><button class="btn good" onclick="quickTeams('${m.id}','${esc(m.start_time)}','${esc(m.phase)}')">Uložit</button></div>`).join(''):'<div class=notice>Žádný zápas k doplnění.</div>'}</div>
  <div id=admin-import class="admin-panel ${adminTab=='import'?'active':''}"><div class=title>Přidat / importovat zápasy</div><label class=admin-field-label>Fáze</label><select id=phaseIn class=input>${phasesList.map(x=>`<option>${x}</option>`).join('')}</select><label class=admin-field-label>Týmy</label><div class=grid2>${teamSelect('homeTeam')} ${teamSelect('awayTeam')}</div><div id=teamPreview class=admin-match-preview></div><label class=admin-field-label>Datum a čas výkopu</label><input id=startTime class=input type=datetime-local><button class="btn primary full" onclick=addMatch()>Přidat zápas</button><div class=add-match-help>Vyber fázi, domácí a hostující tým a hlavně doplň datum a čas. Vlajky se doplní automaticky podle názvů zemí. Po uložení zůstaneš v této záložce.</div><hr style="border:0;border-top:1px solid var(--line);margin:16px 0"><p class=note>Hromadný import: 2026-06-11 21:00; Skupina A; Mexiko; Jihoafrická republika</p><textarea id=bulk class=input></textarea><button class="btn primary full" onclick=imp()>Importovat</button></div>
  <div id=admin-all class="admin-panel ${adminTab=='all'?'active':''}"><div class=title>Pokročilá správa zápasů</div><button class="btn good full" onclick=resetSchedule()>Obnovit pevný rozpis MS 2026</button><div class="admin-note">Použije pevný rozpis uložený přímo v aplikaci. Nic se nestahuje z internetu ani z externího API.</div>${matches.map(m=>`<div class=match><div class=match-head><b>${esc(m.home_flag||'')} ${esc(m.home)} vs ${esc(m.away_flag||'')} ${esc(m.away)}</b>${badge(m)}</div><div class=note>${esc(m.phase)} • ${new Date(m.start_time).toLocaleString('cs-CZ')} ${m.score?'• '+esc(m.score):''}</div><div class=admin-actions><button class="btn small" onclick='editMatch(${JSON.stringify(m).replace(/'/g,"&#39;")})'>Upravit</button><button class="btn small" onclick="setStatus('${m.id}','open')">Otevřít</button><button class="btn small" onclick="setStatus('${m.id}','locked')">Zamknout</button><button class="btn good small" onclick="result('${m.id}')">Výsledek</button><button class="btn small" onclick="setStatus('${m.id}','finished')">Dohráno</button></div></div>`).join('')}</div></div>`;
}
async function refreshSilent(force=false){
  if(!me)return;
  if(Date.now()<editingUntil)return;
  const ae=document.activeElement;
  if(!force && page==='admin' && ae && ['INPUT','TEXTAREA','SELECT'].includes(ae.tagName))return;
  try{data=await api('/app');me=(await api('/me')).user;let sig=renderSignature();if(force||sig!==__lastRenderSignature){render()}}catch(e){}
}

// v51 overrides: lepší pořadí, preview zápasu a bezpečnější přidání zápasu
function rank(){
  let top=data.ranking||[];
  let updated=new Date().toLocaleString('cs-CZ');
  return `<div class=card><div class=rank-legend><b>1b</b> trefená výhra/remíza/prohra · <b>3b</b> přesný výsledek · <b>Body</b> určují pořadí</div><div class=rank-table-wrap><div class=rank-table><div class=rank-head><div>#</div><div>Tipér</div><div>1b</div><div>3b</div><div>Body</div></div>${top.length?top.map((u,i)=>`<div class="rank-row ${u.id==me.id?'my-row':''}"><div class=medal>${i==0?'🥇':i==1?'🥈':i==2?'🥉':i+1}</div><div class=rank-nick title="${displayUser(u)}">${displayUser(u)}</div><div class=rank-cell>${u.hit_1||0}</div><div class=rank-cell>${u.hit_3||0}</div><div class="rank-cell rank-total">${u.points||0}</div></div>`).join(''):'<div class=notice>Zatím nejsou vyhodnocené tipy.</div>'}</div></div><div class=note style="margin-top:8px">Aktualizováno: ${updated}</div></div>`
}
function teamSelect(id,selected=''){
  const opts=(data&&data.teamOptions?data.teamOptions:[]).filter(Boolean);
  return `<select id="${id}" class="input" onchange="updateTeamPreview()">${opts.map(t=>`<option value="${esc(t)}" ${t===selected?'selected':''}>${esc(flagOf(t))} ${esc(t)}</option>`).join('')}</select>`;
}
function updateTeamPreview(){
  const box=document.getElementById('teamPreview');
  if(!box)return;
  const h=document.getElementById('homeTeam')?.value||'';
  const a=document.getElementById('awayTeam')?.value||'';
  box.innerHTML=`<div><b>${esc(flagOf(h))}</b><span>${esc(h||'Domácí')}</span></div><strong>VS</strong><div><b>${esc(flagOf(a))}</b><span>${esc(a||'Hosté')}</span></div>`;
}
async function addMatch(){
  await withBusy('Přidávám…',async()=>{
    const home=document.getElementById('homeTeam')?.value||'';
    const away=document.getElementById('awayTeam')?.value||'';
    const start=document.getElementById('startTime')?.value||'';
    const ph=document.getElementById('phaseIn')?.value||'Zápas';
    if(!home||!away){alert('Vyber oba týmy.');return}
    if(home===away){alert('Vyber dva různé týmy.');return}
    if(!start){alert('Doplň datum a čas výkopu. Bez času se zápas nedá správně zobrazit ani uzamknout.');return}
    adminTab='import';
    let r=await api('/admin/add-match',{method:'POST',body:JSON.stringify({phase:ph,home,away,start_time:start})});
    await refreshSilent(true);
    setTimeout(()=>{setAdminTab('import');updateTeamPreview()},0);
    alert(r.exists?'Zápas už v rozpisu existoval, proto se znovu nepřidal.':'Zápas byl přidán. Vlajky se doplnily automaticky.');
  })
}
function render(){
  const rootEl=document.getElementById('root');
  if(!me){rootEl.innerHTML=loginScreen();return}
  if(!document.getElementById('app-main')){rootEl.innerHTML=topbar()+`<main id=app-main class=app></main>`+nav()}
  updateHeader();
  const main=document.getElementById('app-main'); if(main)main.innerHTML=pageContent();
  updateNav();
  if(page==='admin')setTimeout(updateTeamPreview,0);
  __lastRenderSignature=renderSignature();
  startRealtime();
}

function pageContent(){let pages={home,tips,rank,rules,profile,bets:betsPage,admin};return (pages[page]||home)()}
function updateHeader(){
  if(!me||!data)return;
  const c=competition(),u=userName(),{st,pos,pct,ev}=userStats(),total=st.tips_count||0;
  const sub=document.querySelector('.brand-sub'); if(sub)sub.textContent=c.name||'FIFA World Cup 2026';
  const meta=document.querySelectorAll('.meta-value'); if(meta[0])meta[0].textContent=sectionTitle(); if(meta[1])meta[1].textContent=u;
  const nums=document.querySelectorAll('.stat-chip strong');
  if(nums[0])nums[0].textContent=(pos||'—')+'.'; if(nums[1])nums[1].textContent=st.points||0; if(nums[2])nums[2].textContent=pct+'%'; if(nums[3])nums[3].textContent=ev+'/'+total;
}
function updateNav(){const old=document.querySelector('nav.bottom'); if(old)old.outerHTML=nav()}
function render(){
  const rootEl=document.getElementById('root');
  if(!me){rootEl.innerHTML=loginScreen();return}
  if(!document.getElementById('app-main')){rootEl.innerHTML=topbar()+`<main id=app-main class=app></main>`+nav()}
  updateHeader();
  const main=document.getElementById('app-main'); if(main)main.innerHTML=pageContent();
  updateNav();
  __lastRenderSignature=renderSignature();
  startRealtime();
}


// v66 overrides: domů, profil, orientace v zápasech, testovací úklid
function niceDate(dt){try{return new Date(dt).toLocaleString('cs-CZ',{day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'})}catch(e){return dt||''}}
function nextUntippedMatch(){let now=new Date();return (data.matches||[]).filter(m=>m.effective_status==='open'&&!data.bets.find(b=>b.match_id===m.id)&&new Date(m.start_time)>now).sort((a,b)=>new Date(a.start_time)-new Date(b.start_time))[0]||null}
function nextAnyOpenMatch(){let now=new Date();return (data.matches||[]).filter(m=>m.effective_status==='open'&&new Date(m.start_time)>now).sort((a,b)=>new Date(a.start_time)-new Date(b.start_time))[0]||null}
function lastEvaluatedMatch(){return (data.matches||[]).filter(m=>m.effective_status==='finished'&&m.score).sort((a,b)=>new Date(b.start_time)-new Date(a.start_time))[0]||null}
function home(){
  const p=data.pool||{}, st=data.meStats||me||{}, ev=st.evaluated_count||0, total=st.tips_count||0;
  const next=nextUntippedMatch()||nextAnyOpenMatch();
  const last=lastEvaluatedMatch();
  const missing=(data.matches||[]).filter(m=>m.effective_status==='open'&&!data.bets.find(b=>b.match_id===m.id)).length;
  const fee=(Number(data.settings?.admin_fee||0)+Number(data.settings?.game_fee||0));
  const feeText=fee?`${fee} Kč`:'dle nastavení admina';
  const bank=data.settings?.bank_account||'číslo účtu doplní admin';
  const payNote=`TIP - ${norm((me.first||'')+' '+(me.last||''))||displayUser(me)}`;
  if(me.role!=='player'){
    const waitUsers=(data.users||[]).filter(u=>u.role==='player'&&(!u.approved||!u.paid)).length;
    const waitResults=(data.matches||[]).filter(m=>(m.effective_status==='locked'||new Date(m.start_time)<=new Date())&&!m.score).length;
    return `<div class=home-grid-2><div class="card home-hero"><div class=home-kicker>Admin přehled</div><div class=home-big>Co je potřeba vyřešit</div><div class=admin-health-grid><div><b>${waitUsers}</b><span>čeká hráčů</span></div><div><b>${waitResults}</b><span>výsledků</span></div><div><b>${p.players||0}</b><span>tipérů</span></div><div><b>${(data.matches||[]).length}</b><span>zápasů</span></div></div><div class=home-actions><button class="btn primary" onclick="page='admin';render();setTimeout(()=>setAdminTab&&setAdminTab('todo'),0)">Otevřít admin</button><button class="btn" onclick="page='rank';render()">Pořadí</button></div></div><div class=card><div class=title>Poslední vyhodnocení</div>${last?`<div class=feed-item><b>${esc(last.home_flag||'')} ${esc(last.home)} ${esc(last.score)} ${esc(last.away_flag||'')} ${esc(last.away)}</b><div class=note>${esc(last.phase)} • ${niceDate(last.start_time)}</div></div>`:'<div class=notice>Žádný zápas zatím není vyhodnocený.</div>'}</div></div>`;
  }
  if(!me.approved||!me.paid){
    return `<div class=home-grid-2><div class="card home-hero"><div class=home-kicker>Účet čeká na aktivaci</div><div class=home-big>Dokonči registraci platbou</div><p class=note>Po připsání platby tě administrátor aktivuje a zařadí do soutěže.</p><div class=pay-list><div class=pay-row><span>Startovné</span><b>${esc(feeText)}</b></div><div class=pay-row><span>Číslo účtu</span><b>${esc(bank)}</b></div><div class=pay-row><span>Zpráva / poznámka</span><b>${esc(payNote)}</b></div></div></div><div class=card><div class=title>Co dál?</div><ol class=note><li>Pošli platbu podle údajů vlevo.</li><li>Do poznámky uveď přesně uvedený text.</li><li>Po aktivaci začneš tipovat zápasy.</li></ol><button class="btn full" onclick="page='rules';render()">Přečíst pravidla</button></div></div>`;
  }
  return `<div class=home-grid-2><div class="card home-hero"><div class=home-kicker>Moje soutěž</div><div class=home-big>${missing?`Zbývá tipnout ${missing}`:'Vše otevřené máš tipnuté'}</div><p class=note>Vyhodnoceno <b>${ev}/${total}</b> tvých tipů. Tipy ostatních uvidíš po uzamčení zápasu.</p>${next?`<div class=home-focus><div class=time>Nejbližší ${data.bets.find(b=>b.match_id===next.id)?'otevřený zápas':'netipnutý zápas'} • ${niceDate(next.start_time)}</div><div class=teams-line><span>${esc(next.home_flag||'')} ${esc(next.home)}</span><strong>VS</strong><span>${esc(next.away_flag||'')} ${esc(next.away)}</span></div><button class="btn primary full" onclick="filter='missing';page='tips';render()">Přejít na tipování</button></div>`:''}</div><div class=card><div class=title>Aktuality</div><div class=activity-feed>${last?`<div class=feed-item><b>Poslední výsledek</b><br>${esc(last.home_flag||'')} ${esc(last.home)} ${esc(last.score)} ${esc(last.away_flag||'')} ${esc(last.away)}<div class=note>${esc(last.phase)} • ${niceDate(last.start_time)}</div></div>`:'<div class=feed-item>Výsledky se zde zobrazí po vyhodnocení adminem.</div>'}<div class=feed-item><b>Moje pozice:</b> ${(data.ranking||[]).findIndex(x=>x.id==me.id)+1||'—'}. místo • ${st.points||0} bodů</div></div></div></div>`;
}
function profile(){
  const u=data.meStats||me, pct=u.evaluated_count?Math.round(((u.hit_1||0)+(u.hit_3||0))/(u.evaluated_count||1)*100):0, pos=(data.ranking||[]).findIndex(x=>x.id==u.id)+1;
  return `<div class=card><div class=title>${esc(displayUser(u))}</div><div class=note>Veřejná přezdívka v tabulce. Osobní údaje vidí pouze administrátor.</div><div class="profile-grid" style="margin-top:12px"><div class=profile-stat><b>${pos||'—'}.</b><span>pořadí</span></div><div class=profile-stat><b>${u.points||0}</b><span>bodů</span></div><div class=profile-stat><b>${u.evaluated_count||0}/${u.tips_count||0}</b><span>vyhodnoceno / tipy</span></div><div class=profile-stat><b>${pct}%</b><span>úspěšnost</span></div></div></div><div class=card><div class=title>Údaje z registrace</div><div class=pay-list><div class=pay-row><span>Jméno</span><b>${esc(me.first||'')}</b></div><div class=pay-row><span>Příjmení</span><b>${esc(me.last||'')}</b></div><div class=pay-row><span>Přezdívka</span><b>${esc(displayUser(me))}</b></div><div class=pay-row><span>E-mail</span><b>${esc(me.email||'—')}</b></div><div class=pay-row><span>Role</span><b>${esc(roleLabel(me.role))}</b></div><div class=pay-row><span>Stav účtu</span><b>${me.approved&&me.paid?'Aktivní':'Čeká na aktivaci'}</b></div></div></div><div class=card><div class=title>Platba</div><div class=pay-list><div class=pay-row><span>Poznámka</span><b>${esc(me.payment_note||('TIP - '+(me.first||'')+' '+(me.last||'')))}</b></div><div class=pay-row><span>Účet</span><b>${esc(data.settings?.bank_account||'doplní admin')}</b></div></div></div><div class=card><button class="btn danger full" onclick=out()>Odhlásit</button></div>`;
}
function filtersHtml(){let items=[['all','Vše'],['open','Otevřené'],['missing','Netipnuté'],['tipped','Tipnuté'],['finished','Vyhodnocené']];let total=(data.matches||[]).length,shown=filtered().length,done=(data.matches||[]).filter(m=>m.effective_status==='finished').length,open=(data.matches||[]).filter(m=>m.effective_status==='open').length;let next=nextUntippedMatch()||nextAnyOpenMatch();return `<div class="card filters-card"><div class=filter-grid>${items.map(x=>`<button class="btn ${filter==x[0]?'active':''}" onclick="filter='${x[0]}';render()">${x[1]}</button>`).join('')}</div><select class="input phase-select" onchange="phase=this.value;render()">${phases().map(p=>`<option value="${esc(p)}" ${phase==p?'selected':''}>${p=='all'?'Všechny skupiny a fáze':esc(p)}</option>`).join('')}</select><div class=status-strip><div><b>${shown}</b><span>zobrazeno</span></div><div><b>${done}</b><span>vyhodnoceno</span></div><div><b>${open}</b><span>otevřeno</span></div><div><b>${total}</b><span>celkem</span></div></div>${next?`<div class=match-jump><div><b>Nejbližší k tipování</b><span>${esc(next.home_flag||'')} ${esc(next.home)} vs ${esc(next.away_flag||'')} ${esc(next.away)} • ${niceDate(next.start_time)}</span></div><button class="btn primary" onclick="filter='missing';phase='all';render();setTimeout(()=>document.querySelector('.next-focus')?.scrollIntoView({behavior:'smooth',block:'center'}),80)">Ukázat</button></div>`:''}</div>`}
function tips(){let arr=filtered();let next=nextUntippedMatch()||nextAnyOpenMatch();return filtersHtml()+`<div class=card>${arr.length?arr.map(m=>{let b=data.bets.find(x=>x.match_id==m.id)||{},lock=m.effective_status!='open'||!me.approved||!me.paid||me.role!='player',tipped=!!b.match_id,isNext=next&&m.id===next.id;return `<div class="match ${tipped?'tipped':'missing'} ${isNext?'next-focus':''}"><div class=match-head><div>${badge(m)}</div><div class=note>${new Date(m.start_time).toLocaleString('cs-CZ')} • ${esc(m.phase)} • ${left(m)}</div></div><div class=teams><div class=team><div class=flag>${esc(m.home_flag||'')}</div>${esc(m.home)}</div><div class=score>${m.score?esc(m.score):'VS'}</div><div class=team><div class=flag>${esc(m.away_flag||'')}</div>${esc(m.away)}</div></div><div class=exact>${scoreStepper('h_'+m.id,b.home_goals??0,lock)}<b>:</b>${scoreStepper('a_'+m.id,b.away_goals??0,lock)}</div><div class=tip-actions><button class="btn primary full" ${lock?'disabled':''} onclick="bet('${m.id}')">${tipped?'Upravit tip':'Potvrdit tip'}</button></div>${tipped?`<div class=saved-tip>✓ Uložený tip: ${b.home_goals}:${b.away_goals}</div>`:''}${otherBetsHtml(m)}</div>`}).join(''):'<div class=notice>Pro filtr nejsou zápasy.</div>'}</div>`}
const __admin_v66=admin;
function adminTools(){let playerUsers=(data.users||[]).filter(x=>x.role==='player'),active=playerUsers.filter(x=>x.approved&&x.paid).length,done=(data.matches||[]).filter(x=>x.effective_status==='finished').length,waiting=(data.matches||[]).filter(m=>(m.effective_status==='locked'||new Date(m.start_time)<=new Date())&&!m.score).length;return `<div class=card><div class=title>Kontrola před spuštěním</div><div class=admin-health-grid><div><b>OK</b><span>API</span></div><div><b>${(data.matches||[]).length}/104</b><span>zápasů</span></div><div><b>${active}</b><span>aktivní tipéři</span></div><div><b>${waiting}</b><span>čeká výsledek</span></div></div></div><div class="card admin-danger-zone"><div class=title>Testovací režim</div><p class=note>Použij jen před ostrým spuštěním. Rozpis a hráči zůstanou.</p><div class=grid2><button class="btn danger full" onclick=clearResultsOnly()>Vyčistit výsledky</button><button class="btn danger full" onclick=clearTipsAndResults()>Vyčistit tipy i výsledky</button></div></div>`}
function admin(){return adminTools()+__admin_v66()}
async function clearResultsOnly(){if(!confirm('Smazat všechny testovací výsledky a vrátit zápasy do otevřeného stavu? Tipy hráčů zůstanou.'))return;await withBusy('Čistím…',async()=>{await api('/admin/clear-results',{method:'POST',body:'{}'});await refreshSilent(true);alert('Výsledky byly vyčištěny.')})}
async function clearTipsAndResults(){if(!confirm('Smazat všechny testovací tipy i výsledky? Hráči a rozpis zůstanou.'))return;await withBusy('Čistím…',async()=>{await api('/admin/clear-test-data',{method:'POST',body:'{}'});await refreshSilent(true);alert('Testovací tipy a výsledky byly vyčištěny.')})}


// v67 skupiny soutěže
let publicGroups=[], adminGroupId=localStorage.tip_admin_group||'g-test';
async function loadPublicGroups(){try{let g=await api('/groups');publicGroups=g.groups||[]}catch(e){publicGroups=[{id:'g-test',name:'Pokus / testovací',code:'TEST'}]}}
function groupOptions(selected=''){let gs=(data&&data.groups)||publicGroups||[];if(!gs.length)gs=[{id:'g-test',name:'Pokus / testovací',code:'TEST'}];return gs.map(g=>`<option value="${esc(g.id)}" ${selected==g.id?'selected':''}>${esc(g.name)} (${esc(g.code)})</option>`).join('')}
function selectedAppPath(){let p='/app';if(me&&['admin','superadmin'].includes(me.role)){p+='?group='+encodeURIComponent(adminGroupId||'g-test')}return p}
async function load(silent=false){try{if(tok){let m=await api('/me');me=m.user;data=await api(selectedAppPath());if(data&&data.currentGroup&&!adminGroupId)adminGroupId=data.currentGroup.id}else{me=null;data=null;await loadPublicGroups()}}catch(e){if(!silent)msg=e.message;localStorage.removeItem('tip_token');tok='';me=null;data=null;await loadPublicGroups()}render()}
async function refreshSilent(force=false){if(!me)return;if(Date.now()<editingUntil)return;const ae=document.activeElement;if(!force&&page==='admin'&&ae&&['INPUT','TEXTAREA','SELECT'].includes(ae.tagName))return;try{data=await api(selectedAppPath());me=(await api('/me')).user;let sig=renderSignature();if(force||sig!==__lastRenderSignature){render()}}catch(e){}}
function loginScreen(){let cname='FIFA World Cup 2026';let gsel=`<div class=login-group><label class=note>Skupina soutěže</label><select id=loginGroup class=input>${groupOptions(localStorage.tip_group||'g-test')}</select></div>`;return `<div class=login><div class=login-card><div class=login-brand><img src="app-icon.png?v=67" alt="TIP"><div><div class=login-brand-title>Tipovačka</div><div class=login-brand-sub>${cname}</div></div></div><p class=note>Tipuj výsledky zápasů, sleduj pořadí a porovnej se s ostatními ve své skupině. Veřejně se zobrazuje jen přezdívka.</p><p class="note" style="font-size:11px;opacity:.65">verze v67-skupiny</p>${msg?`<div class="notice bad">${esc(msg)}</div>`:''}${gsel}<div class=grid2><input id=loginFirst class=input autocomplete=given-name placeholder="Jméno"><input id=loginLast class=input autocomplete=family-name placeholder="Příjmení"></div><input id=lp class=input type=password autocomplete=current-password placeholder="Heslo"><div class=login-actions><button class="btn primary full" onclick="login(this)">Přihlásit</button><button class="btn full" onclick="toggleRegister(this)">Registrace</button></div><button class="btn small full" style="margin-top:8px" onclick="showForgot(this)">Zapomenuté heslo</button><div id=forgot class="forgot-box hide"><b>Zapomenuté heslo</b><p class=note>Napiš správci soutěže na <b>tomas.nova9@seznam.cz</b>. Do zprávy uveď jméno, příjmení, přezdívku a skupinu. Správce ti nastaví nové heslo.</p></div><div id=reg class=hide><div class=notice ok>Vyber správnou skupinu. Pořadí, startovné a bank hry se počítají samostatně pro každou skupinu.</div><div class=grid2><input id=first class=input placeholder="Jméno"><input id=last class=input placeholder="Příjmení"></div><input id=nick class=input placeholder="Přezdívka do pořadí"><input id=email class=input placeholder="E-mail"><input id=rp class=input type=password placeholder="Heslo"><input id=code class=input placeholder="Vstupní kód"><button class="btn primary full" onclick="register(this)">Registrovat</button><p class=note>Stávající testovací uživatelé jsou ve skupině Pokus / testovací.</p></div><div class=login-install><b>📱 Přidání na plochu</b><p class=note><b>iPhone:</b> Safari → Sdílet → Přidat na plochu.<br><b>Android:</b> Chrome → menu → Přidat na plochu.</p></div></div></div>`}
async function login(btn){const done=setLoading(btn);try{msg='';const first=norm(document.getElementById('loginFirst')?.value||''),last=norm(document.getElementById('loginLast')?.value||''),pass=document.getElementById('lp')?.value||'',gid=document.getElementById('loginGroup')?.value||'g-test';localStorage.tip_group=gid;let r=await api('/auth/login',{method:'POST',body:JSON.stringify({first,last,name:(first+' '+last).trim(),password:pass,group_id:gid})});tok=r.token;localStorage.tip_token=tok;adminGroupId=gid;localStorage.tip_admin_group=gid;await load()}catch(e){msg=e.message;done();render()}}
async function register(btn){const done=setLoading(btn);try{msg='';const gid=document.getElementById('loginGroup')?.value||'g-test';localStorage.tip_group=gid;let r=await api('/auth/register',{method:'POST',body:JSON.stringify({first:first.value,last:last.value,nick:nick.value,email:email.value,phone:'',password:rp.value,code:code.value,group_id:gid})});tok=r.token;localStorage.tip_token=tok;adminGroupId=gid;localStorage.tip_admin_group=gid;await load()}catch(e){msg=e.message;done();render()}}
const __topbar_v67=topbar;function topbar(){let html=__topbar_v67();if(data&&data.currentGroup){html=html.replace('</div></div></header>',`<div class="group-pill">Skupina: ${esc(data.currentGroup.name)}</div></div></div></header>`)}return html}
function groupAdminPanel(){if(!data||!['admin','superadmin'].includes(me.role))return'';let g=data.currentGroup||{},gs=data.groups||[];return `<div class="card group-panel"><div class=title>Skupiny soutěže</div><div class=admin-group-top><div><label class=note>Právě spravuješ skupinu</label><select class=input onchange="adminGroupId=this.value;localStorage.tip_admin_group=this.value;refreshSilent(true)">${gs.map(x=>`<option value="${esc(x.id)}" ${x.id==g.id?'selected':''}>${esc(x.name)} (${esc(x.code)})</option>`).join('')}</select></div><div class=group-current><span class=note>Kód pro registraci</span><br><b>${esc(g.code||'TEST')}</b></div></div><div class=group-hint>Výsledky zápasů jsou společné pro všechny skupiny. Pořadí, aktivace hráčů, startovné, bank hry a platba se počítají podle vybrané skupiny.</div><details style="margin-top:12px"><summary class=btn>+ Přidat novou skupinu</summary><div class=group-admin-grid style="margin-top:10px"><input id=newGroupName class=input placeholder="Název skupiny, např. Škola"><input id=newGroupCode class=input placeholder="Kód, např. BABAK"><button class="btn primary" onclick=createGroup()>Vytvořit</button></div></details></div>`}
const __admin_v67=admin;function admin(){return groupAdminPanel()+__admin_v67()}
const __saveSettings_v67=saveSettings;async function saveSettings(){await withBusy('Ukládám…',async()=>{await api('/admin/settings',{method:'POST',body:JSON.stringify({group_id:(data.currentGroup&&data.currentGroup.id)||adminGroupId,admin_fee:+af.value||0,game_fee:+gf.value||0,bank_account:bank.value,access_code:access.value,rules_html:rulesText.value,competition_name:compName.value,competition_subtitle:compSub.value,competition_logo_url:''})});await refreshSilent(true);let n=document.getElementById('saveNote');if(n)n.classList.add('show');setTimeout(()=>{let n=document.getElementById('saveNote');if(n)n.classList.remove('show')},1800)})}
async function createGroup(){let name=document.getElementById('newGroupName')?.value||'',code=document.getElementById('newGroupCode')?.value||'';if(!name.trim()){alert('Zadej název skupiny.');return}let r=await api('/admin/create-group',{method:'POST',body:JSON.stringify({name,code})});adminGroupId=r.id;localStorage.tip_admin_group=r.id;await refreshSilent(true);alert('Skupina vytvořena. Kód pro registraci: '+r.code)}

